module RefModule(
  output reg [2:0] cycle,
  input clk,
  input enn
);reg [2:0] register = 3'b000;

    wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    if(!enn)
      register <= (register == 3'b111) ? 3'b000 : register + 1;
    else
      register <= 3'b000;
  end

  assign cycle = register;

endmodule
